const ethers = require('ethers');
const crypto = require('crypto');

class SecureWalletManager {
  constructor() {
    this.provider = null;
    this.encryptedWallet = null;
    this.allowedContracts = new Set();
  }

  initialize(rpcUrl, allowedContractAddresses = []) {
    if (!this.isValidUrl(rpcUrl)) {
      throw new Error('Invalid RPC URL');
    }
    this.provider = new ethers.JsonRpcProvider(rpcUrl);
    allowedContractAddresses.forEach(addr => {
      if (ethers.isAddress(addr)) {
        this.allowedContracts.add(addr.toLowerCase());
      }
    });
  }

  isValidUrl(url) {
    try {
      const parsed = new URL(url);
      return parsed.protocol === 'https:' || parsed.protocol === 'http:';
    } catch {
      return false;
    }
  }

  async loadWalletFromEncryptedSource(encryptionKey) {
    const encryptedPrivateKey = process.env.ENCRYPTED_PRIVATE_KEY;
    if (!encryptedPrivateKey) {
      throw new Error('No encrypted wallet found');
    }

    try {
      const decrypted = this.decrypt(encryptedPrivateKey, encryptionKey);
      const wallet = new ethers.Wallet(decrypted, this.provider);
      this.encryptedWallet = wallet;
      return wallet.address;
    } catch (error) {
      throw new Error('Failed to load wallet');
    }
  }

  decrypt(encryptedData, key) {
    const parts = encryptedData.split(':');
    if (parts.length !== 3) {
      throw new Error('Invalid encrypted data format');
    }

    const iv = Buffer.from(parts[0], 'hex');
    const authTag = Buffer.from(parts[1], 'hex');
    const encrypted = Buffer.from(parts[2], 'hex');

    const keyHash = crypto.createHash('sha256').update(key).digest();
    const decipher = crypto.createDecipheriv('aes-256-gcm', keyHash, iv);
    decipher.setAuthTag(authTag);

    let decrypted = decipher.update(encrypted);
    decrypted = Buffer.concat([decrypted, decipher.final()]);
    return decrypted.toString('utf8');
  }

  encrypt(data, key) {
    const iv = crypto.randomBytes(16);
    const keyHash = crypto.createHash('sha256').update(key).digest();
    const cipher = crypto.createCipheriv('aes-256-gcm', keyHash, iv);

    let encrypted = cipher.update(data, 'utf8');
    encrypted = Buffer.concat([encrypted, cipher.final()]);
    const authTag = cipher.getAuthTag();

    return `${iv.toString('hex')}:${authTag.toString('hex')}:${encrypted.toString('hex')}`;
  }

  validateAddress(address) {
    if (!ethers.isAddress(address)) {
      throw new Error('Invalid Ethereum address');
    }
    return ethers.getAddress(address);
  }

  validateAmount(amount) {
    try {
      const parsed = ethers.parseEther(amount.toString());
      if (parsed <= 0n) {
        throw new Error('Amount must be positive');
      }
      return parsed;
    } catch {
      throw new Error('Invalid amount');
    }
  }

  async sendETH(toAddress, amountInEther, maxGasPrice = null) {
    if (!this.encryptedWallet) {
      throw new Error('Wallet not loaded');
    }

    const validatedAddress = this.validateAddress(toAddress);
    const validatedAmount = this.validateAmount(amountInEther);

    const balance = await this.provider.getBalance(this.encryptedWallet.address);
    if (balance < validatedAmount) {
      throw new Error('Insufficient balance');
    }

    const tx = {
      to: validatedAddress,
      value: validatedAmount,
    };

    if (maxGasPrice) {
      const gasPrice = await this.provider.getFeeData();
      if (gasPrice.gasPrice > ethers.parseUnits(maxGasPrice.toString(), 'gwei')) {
        throw new Error('Gas price exceeds maximum allowed');
      }
    }

    const transaction = await this.encryptedWallet.sendTransaction(tx);
    return {
      hash: transaction.hash,
      from: transaction.from,
      to: transaction.to,
      value: ethers.formatEther(transaction.value)
    };
  }

  async waitForTransaction(txHash, confirmations = 1) {
    if (!/^0x[a-fA-F0-9]{64}$/.test(txHash)) {
      throw new Error('Invalid transaction hash');
    }
    const receipt = await this.provider.waitForTransaction(txHash, confirmations);
    return {
      status: receipt.status === 1 ? 'success' : 'failed',
      blockNumber: receipt.blockNumber,
      gasUsed: receipt.gasUsed.toString()
    };
  }

  async interactWithContract(contractAddress, abi, methodName, params = [], value = '0') {
    if (!this.encryptedWallet) {
      throw new Error('Wallet not loaded');
    }

    const validatedAddress = this.validateAddress(contractAddress);
    
    if (!this.allowedContracts.has(validatedAddress.toLowerCase())) {
      throw new Error('Contract not in allowlist');
    }

    const contract = new ethers.Contract(validatedAddress, abi, this.encryptedWallet);

    if (typeof contract[methodName] !== 'function') {
      throw new Error('Method not found in contract');
    }

    const valueInWei = value !== '0' ? this.validateAmount(value) : 0n;

    const options = valueInWei > 0n ? { value: valueInWei } : {};
    const tx = await contract[methodName](...params, options);
    
    return {
      hash: tx.hash,
      from: tx.from,
      to: tx.to
    };
  }

  async callContractView(contractAddress, abi, methodName, params = []) {
    const validatedAddress = this.validateAddress(contractAddress);
    
    if (!this.allowedContracts.has(validatedAddress.toLowerCase())) {
      throw new Error('Contract not in allowlist');
    }

    const contract = new ethers.Contract(validatedAddress, abi, this.provider);

    if (typeof contract[methodName] !== 'function') {
      throw new Error('Method not found in contract');
    }

    const result = await contract[methodName](...params);
    return result;
  }

  async getBalance(address = null) {
    const targetAddress = address ? this.validateAddress(address) : this.encryptedWallet.address;
    const balance = await this.provider.getBalance(targetAddress);
    return ethers.formatEther(balance);
  }

  async estimateGas(toAddress, amountInEther) {
    const validatedAddress = this.validateAddress(toAddress);
    const validatedAmount = this.validateAmount(amountInEther);

    const gasEstimate = await this.provider.estimateGas({
      to: validatedAddress,
      value: validatedAmount
    });

    return gasEstimate.toString();
  }

  clearWallet() {
    this.encryptedWallet = null;
  }
}

class RateLimiter {
  constructor(maxRequests, windowMs) {
    this.maxRequests = maxRequests;
    this.windowMs = windowMs;
    this.requests = new Map();
  }

  checkLimit(identifier) {
    const now = Date.now();
    const userRequests = this.requests.get(identifier) || [];
    
    const validRequests = userRequests.filter(time => now - time < this.windowMs);
    
    if (validRequests.length >= this.maxRequests) {
      throw new Error('Rate limit exceeded');
    }
    
    validRequests.push(now);
    this.requests.set(identifier, validRequests);
    return true;
  }

  cleanup() {
    const now = Date.now();
    for (const [identifier, requests] of this.requests.entries()) {
      const validRequests = requests.filter(time => now - time < this.windowMs);
      if (validRequests.length === 0) {
        this.requests.delete(identifier);
      } else {
        this.requests.set(identifier, validRequests);
      }
    }
  }
}

